// OpenCL translation of the kmeans_clustering function and related helpers.
// This kernel and helper functions implement the core K-means clustering logic
// that was originally parallelized with OpenMP. 

#pragma OPENCL EXTENSION cl_khr_fp64 : enable

// Euclidean distance squared between two points
inline float euclid_dist_2(__global const float *pt1,
                           __global const float *pt2,
                           const int numdims)
{
    float ans = 0.0f;
    for (int i = 0; i < numdims; i++) {
        float diff = pt1[i] - pt2[i];
        ans += diff * diff;
    }
    return ans;
}

// Find nearest cluster center index for a given point
inline int find_nearest_point(__global const float *pt,
                              const int nfeatures,
                              __global const float *clusters,
                              const int nclusters)
{
    int index = 0;
    float min_dist = FLT_MAX;
    for (int i = 0; i < nclusters; i++) {
        float dist = 0.0f;
        for (int j = 0; j < nfeatures; j++) {
            float diff = pt[j] - clusters[i * nfeatures + j];
            dist += diff * diff;
        }
        if (dist < min_dist) {
            min_dist = dist;
            index = i;
        }
    }
    return index;
}

// Kernel to assign each point to nearest cluster and accumulate partial sums
__kernel void kmeans_assign_points(
    const int npoints,
    const int nfeatures,
    const int nclusters,
    __global const float *features,       // npoints * nfeatures
    __global const float *clusters,       // nclusters * nfeatures
    __global int *membership,             // npoints
    __global float *partial_new_centers,  // nthreads * nclusters * nfeatures
    __global int *partial_new_centers_len // nthreads * nclusters
)
{
    int gid = get_global_id(0);
    int lid = get_local_id(0);
    int lsize = get_local_size(0);
    int group_id = get_group_id(0);

    if (gid >= npoints) return;

    // Find nearest cluster
    __global const float *pt = &features[gid * nfeatures];
    int nearest = 0;
    float min_dist = FLT_MAX;
    for (int c = 0; c < nclusters; c++) {
        float dist = 0.0f;
        for (int f = 0; f < nfeatures; f++) {
            float diff = pt[f] - clusters[c * nfeatures + f];
            dist += diff * diff;
        }
        if (dist < min_dist) {
            min_dist = dist;
            nearest = c;
        }
    }

    int old_membership = membership[gid];
    membership[gid] = nearest;

    // Atomic increments and additions to partial sums
    // Each work-group corresponds to a thread index for partial sums
    int tid = group_id; // Using group id as thread id

    // Compute offsets
    int len_offset = tid * nclusters + nearest;
    int center_offset = (tid * nclusters + nearest) * nfeatures;

    // Atomically increment count
    atomic_inc((volatile __global int *)&partial_new_centers_len[len_offset]);

    // Atomically accumulate features
    for (int f = 0; f < nfeatures; f++) {
        // Use atomic add for floats if available; else use atomic operations on integers
        // OpenCL 2.0 supports atomic_add on floats in global memory
#if __OPENCL_VERSION__ >= 200
        atomic_fetch_add_explicit((volatile __global float *)&partial_new_centers[center_offset + f], pt[f], memory_order_relaxed);
#else
        // Fallback: Use atomic operations on integers by bitcasting floats to ints
        union {
            unsigned int i;
            float f;
        } old_val, new_val;
        volatile __global unsigned int *addr = (volatile __global unsigned int *)&partial_new_centers[center_offset + f];
        do {
            old_val.i = atomic_load(addr);
            new_val.f = old_val.f + pt[f];
        } while (atomic_cmpxchg(addr, old_val.i, as_uint(new_val.f)) != old_val.i);
#endif
    }
}

